var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오오, 바다 건너편에서 먹는 케밥은 역시 맛이 색다르네요.","JPN":"おお、海を越えて食べるケバブの味は格別ですね。","ENG":"Ooh, kebabs sure taste different overseas.","TWN":"哇喔～在大海對面吃沙威瑪特別美味呢～"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님은 안 드세요? 하루 종일 탐문 다니느라 배고프셨잖아요?","JPN":"警視様は食べないんですか？　一日中聞き込み捜査していてお腹空いたでしょ？","ENG":"Aren't you going to eat, Major? You must be starving after spending all day investigating.","TWN":"警政大人不吃嗎？你打聽一整天不餓嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"윽…….","JPN":"うっ……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우린 지금 공무 수행 중이야. 강소영 경위.","JPN":"私たちは今公務遂行中よ、マエカワ警部補。","ENG":"We're on duty right now, Lieutenant Kang.","TWN":"姜素英警衛，我們正在執勤中。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여행 온 관광객처럼 길거리 음식이나 사먹으면서 한가하게 쉴 때가 아니라고.","JPN":"旅行中の観光客みたいに食べ歩きしながらのんびりしている場合じゃないの。","ENG":"Now's not the time to be relaxing and indulging in street food like a tourist.","TWN":"我們不是來玩的觀光客，現在不是買路邊小吃，悠閒休息的時候。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러면요?","JPN":"じゃあどうすれば？","ENG":"It isn't?","TWN":"不然咧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그걸 몰라서 물어?! 이번 대규모 탈옥 사태는 경찰의 명예가 걸린 사태야!","JPN":"そんなこと聞くの！？　今回の大規模脱獄事件は警察の名誉がかかった事件よ！","ENG":"Of course not! The honor of the police is at stake with this mass jailbreak!","TWN":"你是認真的嗎？！這次的大規模越獄事件，害我們警察名譽掃地！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우리가 이러고 있는 동안에도 탈옥한 범죄자들이 무슨 짓을 저지를지 모르잖아!","JPN":"私たちがこうしている間に脱獄囚たちが何をしでかすか心配じゃないの？","ENG":"There's no telling what those escaped convicts are doing as we speak!","TWN":"我們在這邊悠悠哉哉的時候，那些越獄犯說不定正在幹什麼壞事呢！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"에이, 왜 이러실까. 다 먹고 살자고 하는 일인데.","JPN":"え～結局仕事っていいもん食って生きていくためにするもんですよ。","ENG":"Aw, come on. A woman's gotta eat though.","TWN":"哎唷～幹嘛這樣～大家都是混口飯吃嘛～"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"애초에 현지에서 수사에 협조해 주지 않으면 저희 단독으로 움직이는 건 월권이라고요?","JPN":"そもそも現地で捜査に協力してくれなければ、私たちが単独で動くのも越権行為ですよ？","ENG":"Besides, acting on our own without the local police backing us up is a violation of jurisdiction.","TWN":"我們一開始又沒有在當地協助調查，這樣單獨行動是越權好嗎？　"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그리고 이건 엘카노 주교 한 명 잡는다고 끝날 일이 아니에요. 사태를 일으킨 주범이 핵심이죠.","JPN":"それに、これはエルカノ司教を捕まえたところで済む事件でもありませんよ。事件を起こした主犯は別にいますから。","ENG":"Plus, catching Elcano won't solve this either. There's another key player behind the whole case.","TWN":"而且，這件事又不是抓到一個埃爾卡諾主教就真相大白，引發事件的主嫌才是重點。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님이 이런 데서 열내다 쓰러지기라도 하면 청장님한테 멱살 잡힐 사람은 저라고요.","JPN":"警視様がこんなところで頑張りすぎて熱でも出したら、署長に大目玉を食らうのは私ですし。","ENG":"And I wouldn't want you to overwork yourself, only to pass out overseas. The commissioner would have my head.","TWN":"萬一你在這個地方累到昏倒，那局長一定會唯我是問。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥. 과로로 쓰러지는 건 무능력자들한테나 해당되는 얘기고.","JPN":"ふん、過労で倒れるのは無能力者に限った話よ。","ENG":"Hmph. Only the incompetent pass out from exhaustion.","TWN":"哼，沒用的人才會因為過勞而昏倒。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러지 말고 자, 아~ 하세요. 제가 먹여 드리면 되죠?","JPN":"まあまあ、わかったらからあ～んしてください。実は食べたいんでしょ？","ENG":"Come on, don't be like that and open wide. I'll feed you so you won't get your fingers greasy.","TWN":"不要那樣，來，啊～嘴巴張開，我餵你總行了吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위!!","JPN":"マエカワ警部補！！","ENG":"Lieutenant Kang!!","TWN":"姜素英警衛！！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……방금 그 소리, 들었어?","JPN":"……今の音、聞こえた？","ENG":"Did you just hear that?","TWN":"你有聽到那個聲音嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 폭발음이네요.","JPN":"はい、爆発音ですね。","ENG":"Yes. Sounded like an explosion.","TWN":"嗯，是爆炸聲。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};